import React from "react";
import {MenuItem, Menu, Sidebar, SubMenu} from 'react-pro-sidebar';
import './index.css';
import 'bootstrap/dist/css/bootstrap.min.css';
import {BrowserRouter as Router, Routes, Route,  } from 'react-router-dom';

function App() {
return (
  <div className="d-flex" style={{ minHeight: '100vh' }}>
    <Sidebar>
      <Menu>
        <SubMenu label="Menu">
          <MenuItem className="bg-primary text-white rounded">Dashboard</MenuItem>
          <MenuItem>Inventory</MenuItem>
          <MenuItem>Reports</MenuItem>
          <MenuItem>Logout</MenuItem>
        </SubMenu>
      </Menu>
    </Sidebar>

    <div className="flex-grow-1">
      <header className="py-4 border-bottom">
        <h1 className="text-center m-0">
          Warehouse Inventory Application
        </h1>
      </header>

      <main className="p-4">
        <p>Welcome, Ryan! This area is now ready for your inventory tables.</p>
      </main>
    </div>
  </div>
);
}

export default App;
